UPDATE public.brand_story SET description_th = 'พัฒนาจากภูมิปัญญาชาวบ้านสู่งานวิจัย ผลิตภัณฑ์ผ่านกระบวนการผลิตที่ได้มาตรฐานและมีความเฉพาะทาง โดยผลิตตามกระบวนการจากงานวิจัย พร้อมคัดสรรวัตถุดิบคุณภาพสูงที่ได้รับการรับรองมาตรฐาน COA เท่านั้น เพื่อให้คุณมั่นใจในคุณภาพและความปลอดภัยในทุกครั้งที่รับประทาน', description_en = 'Developed from local wisdom to scientific research. Our products go through standardized, specialized manufacturing processes based on research, using only premium ingredients certified by COA standards — so you can be confident in quality and safety every time.', description_zh = '从民间智慧发展到科学研究。产品采用基于研究的标准化、专业化生产工艺，仅选用通过 COA 认证的优质原料，让您每次食用都安心放心。', updated_at = now();